    async def _maybe_commit_trade(self, trade_id: str) -> None:
        t = self.trades.get(trade_id)
        if not t:
            return
        tlock = self._get_trade_lock(trade_id)

        async with tlock:
            if t.status != "open":
                return
            if not (t.a_accept and t.b_accept):
                return

            a_id, b_id = t.a_id, t.b_id
            locks = sorted([self._get_player_lock(a_id), self._get_player_lock(b_id)], key=id)
            async with locks[0]:
                async with locks[1]:
                    async with self._players_lock:
                        a = self.players.get(a_id)
                        b = self.players.get(b_id)
                    if not a or not b:
                        t.status = "cancelled"
                        t.updated_at = _now()
                        await self._broadcast_players({a_id, b_id}, {"type": "trade_update", "trade": self._trade_view(t), "ts": _now()})
                        return

                    # Validate offers against current inventories
                    for item_id, qty in t.a_offer.items():
                        if a.items.get(item_id, 0) < qty:
                            t.status = "cancelled"
                            t.updated_at = _now()
                            await self._broadcast_players({a_id, b_id}, {"type": "trade_update", "trade": self._trade_view(t), "ts": _now(), "reason": "insufficient_a"})
                            return
                    for item_id, qty in t.b_offer.items():
                        if b.items.get(item_id, 0) < qty:
                            t.status = "cancelled"
                            t.updated_at = _now()
                            await self._broadcast_players({a_id, b_id}, {"type": "trade_update", "trade": self._trade_view(t), "ts": _now(), "reason": "insufficient_b"})
                            return

                    # Apply transfer atomically under both player locks
                    async with self._items_lock:
                        for item_id, qty in t.a_offer.items():
                            await self._add_item_to_player(a_id, item_id, -qty)
                            await self._add_item_to_player(b_id, item_id, qty)
                            it = self.items.get(item_id)
                            if it and (a.items.get(item_id, 0) <= 0):
                                await self._set_item_owner(item_id, b_id)
                        for item_id, qty in t.b_offer.items():
                            await self._add_item_to_player(b_id, item_id, -qty)
                            await self._add_item_to_player(a_id, item_id, qty)
                            it = self.items.get(item_id)
                            if it and (b.items.get(item_id, 0) <= 0):
                                await self._set_item_owner(item_id, a_id)

                    t.status = "committed"
                    t.updated_at = _now()

        await self._broadcast_players({t.a_id, t.b_id}, {"type": "trade_update", "trade": self._trade_view(t), "ts": _now()})
        await self._send_inventory_snapshot(t.a_id)
        await self._send_inventory_snapshot(t.b_id)

    async def handle_transfer_direct(self, ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
        pid = await self._require_auth(ws, msg)
        if not pid:
            return
        request_id = msg.get("request_id")
        to_id = msg.get("to_player_id")
        item_id = msg.get("item_id")
        qty = msg.get("qty", 1)

        if not isinstance(to_id, str) or not to_id.strip():
            await self._err(ws, "bad_request", "Missing/invalid to_player_id", request_id)
            return
        if not isinstance(item_id, str) or not item_id.strip():
            await self._err(ws, "bad_request", "Missing/invalid item_id", request_id)
            return
        if not isinstance(qty, int) or qty <= 0:
            await self._err(ws, "bad_request", "Missing/invalid qty", request_id)
            return

        to_id = to_id.strip()
        item_id = item_id.strip()
        if to_id == pid:
            await self._err(ws, "bad_request", "Cannot transfer to self", request_id)
            return

        async with self._players_lock:
            if to_id not in self.players:
                await self._err(ws, "not_found", "Recipient not found", request_id)
                return
            if pid not in self.players:
                await self._err(ws, "not_found", "Sender not found", request_id)
                return

        a_id, b_id = pid, to_id
        locks = sorted([self._get_player_lock(a_id), self._get_player_lock(b_id)], key=id)
        async with locks[0]:
            async with locks[1]:
                async with self._players_lock:
                    a = self.players.get(a_id)
                    b = self.players.get(b_id)
                if not a or not b:
                    await self._err(ws, "not_found", "Player not found", request_id)
                    return
                if a.items.get(item_id, 0) < qty:
                    await self._err(ws, "conflict", "Insufficient quantity", request_id)
                    return

                async with self._items_lock:
                    await self._add_item_to_player(a_id, item_id, -qty)
                    await self._add_item_to_player(b_id, item_id, qty)
                    it = self.items.get(item_id)
                    if it and (a.items.get(item_id, 0) <= 0):
                        await self._set_item_owner(item_id, b_id)

        await self._ok(ws, {"event": "transfer", "to_player_id": to_id, "item_id": item_id, "qty": qty}, request_id)
        await self._send_inventory_snapshot(a_id)
        await self._send_inventory_snapshot(b_id)

